module top_module(
    input signed [15:0] number,
    output reg [15:0] abs_value
);always @* begin
  wire [15:0] _tap_abs_value = abs_value ^ {16{1'b0}};

        if (number < 0) begin
            abs_value <= ~number + 1;
        end
        else begin
            abs_value <= number;
        end
    end

endmodule
